#include <stdio.h>
#include <limits.h>

long long matrixMultiplication(int *nums, int n) {
    int m = n - 1; // number of matrices
    if (m <= 0) return 0;
    static long long dp[100][100]; // n ≤ 100 ⇒ m ≤ 99
    for (int i = 0; i < m; ++i) dp[i][i] = 0;
    for (int len = 2; len <= m; ++len) {
        for (int i = 0; i + len - 1 < m; ++i) {
            int j = i + len - 1;
            long long best = LLONG_MAX;
            for (int k = i; k < j; ++k) {
                long long cost = dp[i][k] + dp[k+1][j] + 1LL * nums[i] * nums[k+1] * nums[j+1];
                if (cost < best) best = cost;
            }
            dp[i][j] = best;
        }
    }
    return dp[0][m-1];
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int nums[101];
        for (int i = 0; i < n; ++i) scanf("%d", &nums[i]);
        long long ans = matrixMultiplication(nums, n);
        printf("%lld\n", ans);
    }
    return 0;
}

