#include <bits/stdc++.h>
using namespace std;

long long solve(const vector<int>& nums) {
    int n = nums.size();
    int m = n - 1; // number of matrices
    if (m <= 0) return 0;
    vector<vector<long long>> dp(m, vector<long long>(m, 0));
    for (int len = 2; len <= m; ++len) {
        for (int i = 0; i + len - 1 < m; ++i) {
            int j = i + len - 1;
            long long best = LLONG_MAX;
            for (int k = i; k < j; ++k) {
                long long cost = dp[i][k] + dp[k+1][j] + 1LL * nums[i] * nums[k+1] * nums[j+1];
                best = min(best, cost);
            }
            dp[i][j] = best;
        }
    }
    return dp[0][m-1];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int n; cin >> n;
        vector<int> nums(n);
        for (int i = 0; i < n; ++i) cin >> nums[i];
        cout << solve(nums) << '\n';
    }
    return 0;
}

