import sys

def solve(nums):
    n = len(nums)
    m = n - 1
    if m <= 0:
        return 0
    dp = [[0] * m for _ in range(m)]
    for length in range(2, m + 1):
        for i in range(0, m - length + 1):
            j = i + length - 1
            best = float('inf')
            for k in range(i, j):
                cost = dp[i][k] + dp[k+1][j] + nums[i] * nums[k+1] * nums[j+1]
                if cost < best:
                    best = cost
            dp[i][j] = best
    return dp[0][m-1]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
        out_lines.append(str(solve(nums)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

